function renderMapping(list){var c=document.getElementById('mappingResults');
if(!list.length){c.innerHTML='<p style="text-align:center;color:var(--text-light);padding:20px;">No sections found. Try a different search.</p>';return;}
c.innerHTML='<table class="limits-table"><thead><tr><th style="width:100px;">Old (1961)</th><th style="width:120px;">New (2025)</th><th>Description</th><th>Category</th><th>Remarks</th></tr></thead><tbody>'+list.map(function(m){
var newCol=m.new==='Omitted'?'<span style="color:var(--danger);font-weight:700;">Omitted</span>':'<strong>'+m.new+'</strong>';
var catColors={preliminary:'#2c5364',exemption:'var(--success)',salary:'#0a8c64',house:'#b5651d',business:'var(--primary-mid)',capital:'#8e44ad',other:'#2980b9',clubbing:'#d35400',deduction:'var(--accent)',assessment:'#7f8c8d',tds:'#c0392b',penalty:'var(--danger)',appeal:'#2c3e50',trust:'#16a085',misc:'#636e72'};
return '<tr><td><strong>'+m.old+'</strong></td><td>'+newCol+'</td><td>'+m.title+'</td><td><span class="tag" style="background:'+(catColors[m.cat]||'#636e72')+'22;color:'+(catColors[m.cat]||'#636e72')+';">'+m.cat+'</span></td><td style="font-size:0.82rem;color:var(--text-light);">'+m.note+'</td></tr>';}).join('')+'</tbody></table>';}

function searchMapping(){var q=document.getElementById('mappingSearch').value.toLowerCase();
var ab=document.querySelector('#mappingFilterRow .filter-btn.active');
var cat=ab?ab.textContent.toLowerCase():'all';
var f=sectionMap;
var catMap={'preliminary':'preliminary','exemptions':'exemption','salary':'salary','house property':'house','business/profession':'business','capital gains':'capital','other sources':'other','clubbing/set off':'clubbing','deductions':'deduction','assessment':'assessment','tds/tcs':'tds','penalty':'penalty','appeals':'appeal','trusts/exempt':'trust','miscellaneous':'misc'};
if(cat!=='all')f=f.filter(function(m){return m.cat===(catMap[cat]||cat);});
if(q)f=f.filter(function(m){return(m.old+' '+m.new+' '+m.title+' '+m.note+' '+m.cat).toLowerCase().indexOf(q)>=0;});
renderMapping(f);}

function filterMapping(cat,btn){document.querySelectorAll('#mappingFilterRow .filter-btn').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');searchMapping();}

renderMapping(sectionMap);


// ==============================
// ITR FORM APPLICABILITY CHECKER
// ==============================
function checkITRForm(){
var entity=document.getElementById('itrEntity').value;
var res=document.getElementById('itrResStatus').value;
var salary=document.getElementById('itrSalary').checked;
var hp1=document.getElementById('itrHP1').checked;
var hp2=document.getElementById('itrHP2').checked;
var bizPres=document.getElementById('itrBizPresumptive').checked;
var bizReg=document.getElementById('itrBizRegular').checked;
var ltcg=document.getElementById('itrLTCG').checked;
var stcg=document.getElementById('itrSTCG').checked;
var other=document.getElementById('itrOther').checked;
var agri=document.getElementById('itrAgri').checked;
var foreign=document.getElementById('itrForeign').checked;
var fno=document.getElementById('itrFnO').checked;
var intraday=document.getElementById('itrIntraday').checked;
var shareBiz=document.getElementById('itrShareBiz').checked;
var shareCG=document.getElementById('itrShareCG').checked;
var crypto=document.getElementById('itrCrypto').checked;
var partnership=document.getElementById('itrPartnership').checked;
var lottery=document.getElementById('itrLottery').checked;
var over50L=document.getElementById('itrOver50L').value==='yes';
var turnover=parseFloat(document.getElementById('itrTurnover').value)||0;

if(!entity){document.getElementById('itrResult').innerHTML='<div class="result-box applicable"><div class="result-title">Please select an Entity Type</div></div>';return;}

var hasCG=ltcg||stcg||shareCG;
var hasBiz=bizPres||bizReg||fno||intraday||shareBiz;
var hasBizRegular=bizReg||fno||intraday||shareBiz;
var hasBizPresOnly=bizPres&&!hasBizRegular;

var form='';var reason='';var schedules=[];var mistakes=[];var cls='applicable';

// Trust
if(entity==='trust'){
form='ITR-7';reason='Trusts and institutions filing under Sec 139(4A)/(4B)/(4C)/(4D) must file ITR-7.';cls='presumptive';
schedules=['Schedule AI (Application of Income)','Schedule HP (House Property)','Schedule CG (Capital Gains)','Schedule OS (Other Sources)','Schedule VC (Voluntary Contributions)','Schedule IE (Income & Expenditure Statement)'];
mistakes=['Not filing Form 10B/10BB audit report before ITR-7 due date','Failing to report corpus donations separately','Not maintaining 85% application of income rule compliance'];
}
// Company
else if(entity==='company'){
form='ITR-6';reason='All companies (other than those claiming exemption under Sec 11) must file ITR-6.';cls='presumptive';
schedules=['Schedule BP (Business/Profession)','Schedule CG (Capital Gains)','Schedule OS (Other Sources)','Schedule MAT (Minimum Alternate Tax)','Schedule AL (Assets & Liabilities if income >50L)','Schedule SH (Shareholding)','Schedule CSR (if applicable)'];
mistakes=['Not reconciling book profit with MAT computation','Missing Schedule SH (shareholding details)','Not reporting related party transactions in Schedule'];
}
// Firm (not LLP), LLP, AOP/BOI
else if(entity==='firm'||entity==='llp'||entity==='aop'){
if(entity==='firm'&&hasBizPresOnly&&!over50L&&!hasCG&&!foreign&&!hasBizRegular){
form='ITR-4 (Sugam)';reason='Partnership Firm (not LLP) with only presumptive income u/s 44AD/44ADA/44AE and total income up to Rs 50L can file ITR-4.';cls='not-applicable';
schedules=['Schedule BP (Presumptive Income)','Schedule TDS','Part A-General (Firm details)'];
mistakes=['Filing ITR-4 as LLP (not allowed)','Not reporting partner remuneration/interest details','Exceeding Rs 50L total income limit'];
}else{
form='ITR-5';reason=(entity==='firm'?'Partnership Firm':entity==='llp'?'LLP':'AOP/BOI')+' must file ITR-5 for all income types (including business, CG, etc.).';cls='presumptive';
schedules=['Schedule BP (Business/Profession)','Schedule CG (Capital Gains)','Schedule OS (Other Sources)','Schedule Partner (details of partners and their share)','Schedule AL (if income >50L)'];
mistakes=['Not reporting partners\' remuneration and interest computation','Missing Schedule Partner details','Not reconciling with partners\' individual ITRs'];
}
}
// Individual / HUF
else if(entity==='individual'||entity==='huf'){
// ITR-3: Has business income (regular) or F&O / intraday / share trading as business
if(hasBizRegular){
form='ITR-3';reason='Individual/HUF with business or professional income (including F&O, intraday trading, or share trading treated as business) must file ITR-3.';
if(fno)reason+=' F&O income is treated as non-speculative business income.';
if(intraday)reason+=' Intraday trading is treated as speculative business income.';
if(shareBiz)reason+=' Delivery-based share trading reported as business income requires ITR-3.';
cls='applicable';
schedules=['Schedule BP (Business/Profession)','Schedule P&L (Profit & Loss)','Schedule BS (Balance Sheet)','Schedule CG (if capital gains)','Schedule OS (Other Sources)','Schedule AL (if income >50L)'];
if(fno)schedules.push('Schedule Speculative Income / Non-Speculative');
if(crypto)schedules.push('Schedule VDA (Virtual Digital Assets — Sec 115BBH)');
mistakes=['Not maintaining books of account for F&O/intraday','Treating F&O loss as capital loss (it is business loss)','Not filing tax audit if turnover exceeds Rs 10 Cr (1 Cr if cash transactions >5%)','Missing balance sheet and P&L in ITR-3'];
}
// ITR-4: Only presumptive business, no CG, no foreign, income <=50L
else if(hasBizPresOnly&&!hasCG&&!foreign&&!over50L&&!hp2&&!crypto&&!lottery){
form='ITR-4 (Sugam)';reason='Individual/HUF with presumptive income under Sec 44AD/44ADA/44AE, total income up to Rs 50L, no capital gains, and no foreign assets can file ITR-4.';cls='not-applicable';
schedules=['Schedule BP (Presumptive Income — 44AD/44ADA)','Schedule TDS','Schedule 80G/80C (if old regime)'];
mistakes=['Filing ITR-4 when turnover exceeds Rs 3 Cr (44AD) or Rs 75L (44ADA)','Declaring profit below 8%/6% without maintaining books','Not maintaining books if opted out of presumptive and came back'];
}
// ITR-1: Resident individual, salary + 1HP + other sources, <=50L, no CG, no business, no foreign
else if(entity==='individual'&&res==='resident'&&!hasBiz&&!hasCG&&!foreign&&!over50L&&!hp2&&!agri&&!crypto&&!partnership&&!lottery&&!fno&&!intraday&&!shareBiz){
form='ITR-1 (Sahaj)';reason='Resident Individual with income from Salary, one House Property, and Other Sources only, with total income up to Rs 50L — eligible for ITR-1.';cls='not-applicable';
if(hp1)reason+=' One house property income is allowed in ITR-1.';
reason+=' ITR-1 CANNOT be filed if: (a) Director in any company, (b) holds unlisted equity shares at any time during the year, (c) TDS u/s 194N (cash withdrawal), (d) agricultural income >Rs 5,000, (e) more than one house property, (f) brought forward/carry forward losses under any head.';
schedules=['Part B — TI (Total Income computation)','Schedule TDS (Form 26AS verification)','Schedule 80C/80D (if old regime)','Schedule IT (Advance/Self-Assessment Tax)'];
mistakes=['Filing ITR-1 when you are a Director in any company (use ITR-2)','Filing ITR-1 while holding unlisted equity shares (use ITR-2)','Filing ITR-1 with agricultural income exceeding Rs 5,000','Filing ITR-1 with TDS deducted u/s 194N on cash withdrawals','Filing ITR-1 when there are brought forward losses to be carried forward','Not verifying Form 26AS / AIS before filing','Claiming HRA exemption without rent receipts','Filing ITR-1 when total income exceeds Rs 50 Lakh'];
}
// ITR-2: Individual/HUF, no business, but has CG/foreign/multiple HP/>50L
else if(!hasBiz){
form='ITR-2';reason='Individual/HUF without business income but with ';
var reasons=[];
if(hasCG)reasons.push('capital gains');
if(foreign)reasons.push('foreign income/assets');
if(hp2)reasons.push('more than one house property');
if(over50L)reasons.push('total income exceeding Rs 50 Lakh');
if(res!=='resident'&&entity==='individual')reasons.push('non-resident/RNOR status');
if(agri)reasons.push('agricultural income >Rs 5,000');
if(crypto)reasons.push('crypto/VDA income');
if(lottery)reasons.push('lottery/winnings income');
if(partnership)reasons.push('share of profit from partnership');
if(reasons.length===0)reasons.push('income not eligible for ITR-1');
reason+=reasons.join(', ')+' must file ITR-2.';
cls='applicable';
schedules=['Schedule CG (Capital Gains — LTCG/STCG)','Schedule OS (Other Sources)','Schedule HP (House Property)','Schedule AL (Assets & Liabilities if income >50L)','Schedule FSI (Foreign Source Income — if applicable)','Schedule FA (Foreign Assets — if applicable)'];
if(crypto)schedules.push('Schedule VDA (Virtual Digital Assets — Sec 115BBH)');
if(shareCG)schedules.push('Schedule 112A/111A (Listed securities CG)');
mistakes=['Not reporting foreign assets even if no foreign income','Not bifurcating LTCG and STCG correctly','Missing Schedule AL when income exceeds Rs 50 Lakh','Not claiming Sec 54/54F exemption with proper documentation'];
}
// Fallback for mixed presumptive + CG etc → ITR-3
else{
form='ITR-3';reason='Individual/HUF with business income along with capital gains, foreign assets, or other complex income must file ITR-3 (cannot use ITR-4 due to capital gains/foreign assets).';cls='applicable';
schedules=['Schedule BP','Schedule CG','Schedule OS','Schedule P&L','Schedule BS','Schedule AL (if >50L)'];
if(crypto)schedules.push('Schedule VDA');
mistakes=['Not maintaining books despite having regular business income','Incorrect head classification between business and capital gains'];
}
}else{
form='ITR-3';reason='Based on your selections, ITR-3 is applicable for Individual/HUF with business income and other complex income sources.';cls='applicable';
schedules=['Schedule BP','Schedule CG','Schedule OS','Schedule P&L','Schedule BS'];
mistakes=['Incorrect classification of income heads','Not maintaining proper books of account'];
}

var html='<div class="result-box '+cls+'" style="display:block;">';
html+='<div class="result-title" style="font-size:1.2rem;color:var(--primary-mid);">Applicable Form: '+form+'</div>';
html+='<div class="result-detail"><p style="margin-bottom:12px;">'+reason+'</p>';
html+='<h4 style="color:var(--primary-light);margin:12px 0 6px;">Key Schedules to Fill:</h4><ul>';
schedules.forEach(function(s){html+='<li>'+s+'</li>';});
html+='</ul>';
html+='<h4 style="color:var(--danger);margin:12px 0 6px;">Common Mistakes to Avoid:</h4><ul>';
mistakes.forEach(function(m){html+='<li style="color:#c0392b;">'+m+'</li>';});
html+='</ul>';
if(over50L)html+='<p style="margin-top:10px;padding:8px 12px;background:#fef9e7;border-radius:6px;font-size:0.85rem;"><strong>Note:</strong> Income exceeds Rs 50 Lakh — <strong>Schedule AL (Assets & Liabilities)</strong> is mandatory. Report all movable/immovable assets and liabilities as on 31st March.</p>';
if(crypto)html+='<p style="margin-top:8px;padding:8px 12px;background:#eaf2f8;border-radius:6px;font-size:0.85rem;"><strong>Crypto/VDA:</strong> Income taxed flat @30% u/s 115BBH. No deduction except cost of acquisition. TDS u/s 194S @1% on transfer. Losses cannot be set off against any other income.</p>';
if(foreign)html+='<p style="margin-top:8px;padding:8px 12px;background:#fde8e8;border-radius:6px;font-size:0.85rem;"><strong>Foreign Assets:</strong> Mandatory reporting in Schedule FA even if no income earned. Non-disclosure attracts penalty under Black Money Act (Rs 10 Lakh).</p>';
html+='</div></div>';
document.getElementById('itrResult').innerHTML=html;
}

function resetITRForm(){
document.getElementById('itrEntity').value='';
document.getElementById('itrResStatus').value='resident';
document.getElementById('itrOver50L').value='no';
document.getElementById('itrTurnover').value='';
var checks=['itrSalary','itrHP1','itrHP2','itrBizPresumptive','itrBizRegular','itrLTCG','itrSTCG','itrOther','itrAgri','itrForeign','itrFnO','itrIntraday','itrShareBiz','itrShareCG','itrCrypto','itrPartnership','itrLottery'];
checks.forEach(function(id){document.getElementById(id).checked=false;});
document.getElementById('itrResult').innerHTML='';
}


