var activeDueCat='all';
var activeDueMonth='all';

function renderDueDates(){
var container=document.getElementById('calendarResults');
var today=new Date().toISOString().slice(0,10);
var filtered=dueDates.filter(function(d){
if(activeDueCat!=='all'&&d.cat!==activeDueCat)return false;
if(activeDueMonth!=='all'&&d.date.slice(5,7)!==activeDueMonth)return false;
return true;
});
filtered.sort(function(a,b){return a.date.localeCompare(b.date);});
if(!filtered.length){container.innerHTML='<p style="color:var(--text-light);padding:20px;">No due dates found for the selected filter.</p>';return;}

var catColors={it:'#2F5496',gst:'#00b894',tds:'#e17055',roc:'#6c5ce7',audit:'#fdcb6e',pf:'#2ecc71',esic:'#3498db'};
var catLabels={it:'Income Tax',gst:'GST',tds:'TDS/TCS',roc:'ROC/MCA',audit:'Audit',pf:'PF/EPF',esic:'ESIC'};
var today2=new Date().toISOString().slice(0,10);var fifteenLater=new Date(new Date(today2).getTime()+15*86400000).toISOString().slice(0,10);
var totalCount=filtered.length;var pastCount=filtered.filter(function(d){return d.date<today2;}).length;var upcomingCount=filtered.filter(function(d){return d.date>=today2&&d.date<=fifteenLater;}).length;var scheduledCount=totalCount-pastCount-upcomingCount;
var html='<div style="display:flex;flex-wrap:wrap;gap:12px;margin-bottom:14px;"><div style="flex:1;min-width:140px;background:#eaf2f8;border-radius:8px;padding:10px 14px;text-align:center;"><div style="font-size:1.3rem;font-weight:800;color:var(--primary-mid);">'+totalCount+'</div><div style="font-size:0.78rem;color:var(--text-light);font-weight:600;">Total Obligations</div></div><div style="flex:1;min-width:140px;background:#fde8e8;border-radius:8px;padding:10px 14px;text-align:center;"><div style="font-size:1.3rem;font-weight:800;color:#e74c3c;">'+pastCount+'</div><div style="font-size:0.78rem;color:var(--text-light);font-weight:600;">Past Due</div></div><div style="flex:1;min-width:140px;background:#fef9e7;border-radius:8px;padding:10px 14px;text-align:center;"><div style="font-size:1.3rem;font-weight:800;color:#e67e22;">'+upcomingCount+'</div><div style="font-size:0.78rem;color:var(--text-light);font-weight:600;">Upcoming (15 days)</div></div><div style="flex:1;min-width:140px;background:#e8f8f5;border-radius:8px;padding:10px 14px;text-align:center;"><div style="font-size:1.3rem;font-weight:800;color:#27ae60;">'+scheduledCount+'</div><div style="font-size:0.78rem;color:var(--text-light);font-weight:600;">Scheduled</div></div></div>';
html+='<table class="limits-table"><thead><tr><th>Due Date</th><th>Category</th><th>Obligation</th><th>Details</th><th>Status</th></tr></thead><tbody>';
filtered.forEach(function(d){
var isPast=d.date<today;
var isUpcoming=!isPast&&d.date<=new Date(new Date(today).getTime()+15*86400000).toISOString().slice(0,10);
var status=isPast?'<span style="color:#e74c3c;font-weight:700;">⏰ Past Due</span>':isUpcoming?'<span style="color:#e67e22;font-weight:700;">⚡ Upcoming</span>':'<span style="color:#27ae60;">✓ Scheduled</span>';
var dateObj=new Date(d.date+'T00:00:00');
var dateStr=dateObj.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'});
var catBadge='<span style="background:'+catColors[d.cat]+';color:white;padding:2px 8px;border-radius:10px;font-size:0.72rem;">'+catLabels[d.cat]+'</span>';
var rowBg=isPast?'background:rgba(231,76,60,0.06);':'';
html+='<tr style="'+rowBg+'"><td><strong>'+dateStr+'</strong></td><td>'+catBadge+'</td><td>'+d.title+'</td><td style="font-size:0.82rem;color:#555;">'+d.detail+'</td><td>'+status+'</td></tr>';
});
html+='</tbody></table>';
container.innerHTML=html;
}

function filterDueDates(cat,btn){
activeDueCat=cat;
applyDueFilters(btn);
}
function filterDueMonth(m,btn){
activeDueMonth=m;
applyDueFilters(btn);
}
function applyDueFilters(btn){
if(btn){btn.parentElement.querySelectorAll('.filter-btn').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');}
renderDueDates();
}


// ==================== FORM 15CA/15CB JS ====================
function check15CA(){
  var nature=document.getElementById('fcNature').value;
  var amount=parseFloat(document.getElementById('fcAmount').value)||0;
  var ca=document.getElementById('fcCA').value;
  var dtaaEl=document.getElementById('fcDTAA');
  var dtaa=dtaaEl.value;
  var dtaaCountry=dtaaEl.options[dtaaEl.selectedIndex].getAttribute('data-country')||'';
  var cert=document.getElementById('fcCert').value;
  var r=document.getElementById('fcResult');
  if(!nature){r.className='result-box applicable';r.innerHTML='<div class="result-title">Select nature of remittance</div>';return;}

  var isExempt = nature.indexOf('exempt')>=0 || nature==='dtaa_exempt';
  var part='',need15CB=false,reason='';

  if(isExempt){
    part='Part D';need15CB=false;
    reason='Payment is exempt under Rule 37BB / not chargeable to tax / exempt under DTAA. File Part D of Form 15CA.';
  } else if(amount<=500000){
    part='Part A';need15CB=false;
    reason='Taxable remittance but amount does not exceed Rs 5,00,000 in the FY. File Part A of Form 15CA.';
  } else if(cert==='yes'){
    part='Part B';need15CB=false;
    reason='Taxable remittance exceeding Rs 5 lakh with order/certificate u/s 195(2)/195(3)/197 [Sec 396(2)/396(3)/389 of IT Act 2025] obtained. File Part B of Form 15CA.';
  } else {
    part='Part C';need15CB=true;
    reason='Taxable remittance exceeding Rs 5 lakh without any order or exemption. Obtain Form 15CB from CA first, then file Part C of Form 15CA.';
  }

  r.className='result-box presumptive';
  var html='<div class="result-title">Form 15CA — '+part+'</div>';
  html+='<div class="result-detail"><table class="limits-table" style="margin-top:10px;">';
  html+='<tr><td>Form 15CA Required?</td><td><strong style="color:'+(isExempt?'#e67e22':'#27ae60')+';">'+(isExempt?'Yes (Part D)':'Yes')+'</strong></td></tr>';
  html+='<tr><td>Applicable Part</td><td><strong>'+part+'</strong></td></tr>';
  html+='<tr><td>Form 15CB (CA Certificate) Required?</td><td><strong style="color:'+(need15CB?'#d63031':'#27ae60')+';">'+(need15CB?'YES — Obtain before filing Part C':'No')+'</strong></td></tr>';
  html+='<tr><td>Reason</td><td>'+reason+'</td></tr>';
  if(dtaa==='yes'&&dtaaCountry){
    html+='<tr><td>DTAA Country</td><td><strong style="color:#2980b9;">'+dtaaCountry+'</strong> — Apply DTAA rate or IT Act rate, whichever is lower. Obtain TRC from '+dtaaCountry+' before remittance.</td></tr>';
  } else if(dtaa==='notsure'){
    html+='<tr><td>DTAA</td><td style="color:#f39c12;font-weight:600;">Not Sure — Check if India has a DTAA with the payee\'s country. If yes, obtain TRC and apply beneficial rate.</td></tr>';
  }
  html+='</table>';
  if(need15CB) html+='<p style="margin-top:10px;color:#d63031;font-weight:600;">Remitter files Form 15CA online on IT Portal | CA must issue Form 15CB BEFORE Part C is filed</p>';
  if(!isExempt) html+='<p style="margin-top:8px;color:#e67e22;font-size:0.85rem;">⚠ Penalty u/s 271-I (Sec 453 IT Act 2025): Rs 1,00,000 for failure to furnish Form 15CA or furnishing inaccurate particulars.</p>';
  html+='<p style="margin-top:6px;color:#27ae60;font-size:0.78rem;">📘 IT Act 2025 cross-refs: Sec 195→396 · Sec 197→389 · Sec 271-I→453 · Rule 37BB continues</p>';
  html+='</div>';
  r.innerHTML=html;
}
function reset15CA(){['fcAmount'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('fcNature').value='';document.getElementById('fcCA').value='no';document.getElementById('fcDTAA').value='no';document.getElementById('fcCert').value='no';document.getElementById('fcResult').className='result-box';document.getElementById('fcResult').innerHTML='';}


