// ==================== PARTNERSHIP 40(b) JS ====================
function calc40b(){
  var ay=document.getElementById('pAY').value;
  var partners=parseInt(document.getElementById('pPartners').value)||0;
  var remun=parseFloat(document.getElementById('pRemun').value)||0;
  var interest=parseFloat(document.getElementById('pInterest').value)||0;
  var intRate=parseFloat(document.getElementById('pIntRate').value)||12;
  var capital=parseFloat(document.getElementById('pCapital').value)||0;
  var profit=parseFloat(document.getElementById('pProfit').value)||0;
  var remDebited=document.getElementById('pRemDebited').value;
  var intDebited=document.getElementById('pIntDebited').value;
  var presumptive=document.getElementById('pPresumptive').value;
  var r=document.getElementById('pResult');

  if(presumptive==='yes'){r.className='result-box applicable';r.innerHTML='<div class="result-title" style="color:#d63031;">Not Applicable</div><div class="result-detail">Remuneration deduction u/s 40(b) is NOT available to firms taxed under Sec 44AD or 44ADA.</div>';return;}
  if(!profit&&!remun){r.className='result-box applicable';r.innerHTML='<div class="result-title">Enter firm details</div>';return;}

  var bookProfit=profit;
  if(remDebited==='yes') bookProfit+=remun;
  if(intDebited==='yes') bookProfit+=interest;

  var maxInt=Math.round(capital*12/100);
  if(intRate>12) intRate=12;
  var actualInt=interest;
  var allowInt=Math.min(actualInt,maxInt);
  var disallowInt=actualInt-allowInt;

  var isNew = ay!=='old';
  var firstSlab=isNew?600000:300000;
  var minAmount=isNew?300000:150000;
  var maxRemun=0;

  if(bookProfit<=0){
    maxRemun=minAmount;
  } else if(bookProfit<=firstSlab){
    var calc90=Math.round(bookProfit*0.9);
    maxRemun=Math.max(minAmount,calc90);
  } else {
    var onFirst=Math.max(minAmount,Math.round(firstSlab*0.9));
    var onBalance=Math.round((bookProfit-firstSlab)*0.6);
    maxRemun=onFirst+onBalance;
  }

  var allowRemun=Math.min(remun,maxRemun);
  var disallowRemun=remun-allowRemun;

  var taxableIncome=bookProfit-allowRemun-allowInt;
  if(taxableIncome<0) taxableIncome=0;

  var tax=Math.round(taxableIncome*0.3);
  var surcharge=taxableIncome>10000000?Math.round(tax*0.12):0;
  var cess=Math.round((tax+surcharge)*0.04);
  var totalTax=tax+surcharge+cess;

  r.className='result-box presumptive';
  var html='<div class="result-title">Section 40(b) Computation — '+(isNew?'AY 2025-26 onwards (Finance Act 2024)':'Up to AY 2024-25')+'</div>';
  html+='<div class="result-detail">';
  html+='<h3 style="margin:10px 0 6px;color:var(--accent);">Step A — Book Profit</h3>';
  html+='<table class="limits-table"><tr><td>Net Profit as per P&L</td><td>'+fmt(profit)+'</td></tr>';
  if(remDebited==='yes') html+='<tr><td>(+) Add back: Remuneration debited</td><td>'+fmt(remun)+'</td></tr>';
  if(intDebited==='yes') html+='<tr><td>(+) Add back: Interest debited</td><td>'+fmt(interest)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Book Profit u/s 40(b)</strong></td><td><strong>'+fmt(bookProfit)+'</strong></td></tr></table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step B — Allowable Interest u/s 40(b)(iv)</h3>';
  html+='<table class="limits-table"><tr><td>Max rate: 12% on capital '+fmt(capital)+'</td><td>'+fmt(maxInt)+'</td></tr>';
  html+='<tr><td>Actual interest paid</td><td>'+fmt(actualInt)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Allowable Interest</strong></td><td><strong>'+fmt(allowInt)+'</strong></td></tr>';
  if(disallowInt>0) html+='<tr style="background:#fde8e8;"><td>Disallowance</td><td style="color:#d63031;">'+fmt(disallowInt)+'</td></tr>';
  html+='</table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step C — Allowable Remuneration u/s 40(b)(v)</h3>';
  html+='<table class="limits-table">';
  if(bookProfit<=0){
    html+='<tr><td>Book profit is nil/negative</td><td>Max = '+fmt(minAmount)+'</td></tr>';
  } else {
    html+='<tr><td>On first '+fmt(firstSlab)+' of book profit</td><td>'+fmt(Math.max(minAmount,Math.round(Math.min(bookProfit,firstSlab)*0.9)))+'</td></tr>';
    if(bookProfit>firstSlab) html+='<tr><td>On balance '+fmt(bookProfit-firstSlab)+' @ 60%</td><td>'+fmt(Math.round((bookProfit-firstSlab)*0.6))+'</td></tr>';
  }
  html+='<tr><td><strong>Maximum Allowable</strong></td><td><strong>'+fmt(maxRemun)+'</strong></td></tr>';
  html+='<tr><td>Actual paid</td><td>'+fmt(remun)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Allowable Remuneration</strong></td><td><strong>'+fmt(allowRemun)+'</strong></td></tr>';
  if(disallowRemun>0) html+='<tr style="background:#fde8e8;"><td>Disallowance u/s 40(b)</td><td style="color:#d63031;">'+fmt(disallowRemun)+'</td></tr>';
  html+='</table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step D & E — Taxable Income & Tax</h3>';
  html+='<table class="limits-table">';
  html+='<tr><td>Book Profit</td><td>'+fmt(bookProfit)+'</td></tr>';
  html+='<tr><td>(-) Allowable Remuneration</td><td>'+fmt(allowRemun)+'</td></tr>';
  html+='<tr><td>(-) Allowable Interest</td><td>'+fmt(allowInt)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Taxable Income of Firm</strong></td><td><strong>'+fmt(taxableIncome)+'</strong></td></tr>';
  html+='<tr><td>Tax @ 30%</td><td>'+fmt(tax)+'</td></tr>';
  if(surcharge>0) html+='<tr><td>Surcharge @ 12%</td><td>'+fmt(surcharge)+'</td></tr>';
  html+='<tr><td>Health & Education Cess @ 4%</td><td>'+fmt(cess)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Total Tax Liability</strong></td><td><strong>'+fmt(totalTax)+'</strong></td></tr>';
  html+='</table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step F — Partners\' Position</h3>';
  html+='<table class="limits-table">';
  html+='<tr><td>Share of profit in partners\' hands</td><td><strong style="color:#27ae60;">Exempt u/s 10(2A)</strong></td></tr>';
  html+='<tr><td>Remuneration received</td><td>Taxable as Business Income u/s 28(v)</td></tr>';
  html+='<tr><td>Interest received</td><td>Taxable as Business Income u/s 28(v)</td></tr>';
  html+='<tr style="background:#fef9e7;"><td>TDS u/s 194T (w.e.f. 01.04.2025)</td><td>10% if total > Rs 20,000 in FY</td></tr>';
  html+='</table></div>';
  r.innerHTML=html;
}
