// ==================== ITR-U JS ====================
function confirmITRU(){
  document.getElementById('itruCalcSection').style.display='block';
  document.getElementById('itruConfirmBtn').textContent='Confirmed — Calculator Enabled';
  document.getElementById('itruConfirmBtn').disabled=true;
  document.getElementById('itruConfirmBtn').style.opacity='0.5';
}
function calcITRU(){
  var ay=document.getElementById('itruAY').value;
  var dateStr=document.getElementById('itruDate').value;
  var income=parseFloat(document.getElementById('itruIncome').value)||0;
  var rate=parseFloat(document.getElementById('itruRate').value)||30;
  var tds=parseFloat(document.getElementById('itruTDS').value)||0;
  var advTax=parseFloat(document.getElementById('itruAdvTax').value)||0;
  var r=document.getElementById('itruResult');

  if(!income||!ay){r.className='result-box applicable';r.innerHTML='<div class="result-title">Enter details</div>';return;}

  var ayEndYear=parseInt(ay.split('-')[1])+2000;
  var ayEnd=new Date(ayEndYear,2,31);

  var fileDate=dateStr?new Date(dateStr):new Date();

  var diffMs=fileDate.getTime()-ayEnd.getTime();
  var diffMonths=diffMs/(1000*60*60*24*30.44);

  var window_num=0,addRate=0,windowLabel='';
  if(diffMonths<=12){window_num=1;addRate=25;windowLabel='Window 1 (within 12 months)';}
  else if(diffMonths<=24){window_num=2;addRate=50;windowLabel='Window 2 (12-24 months)';}
  else if(diffMonths<=36){window_num=3;addRate=60;windowLabel='Window 3 (24-36 months — FA 2025)';}
  else if(diffMonths<=48){window_num=4;addRate=70;windowLabel='Window 4 (36-48 months — FA 2025)';}
  else{r.className='result-box applicable';r.innerHTML='<div class="result-title" style="color:#d63031;">Time Barred</div><div class="result-detail">ITR-U cannot be filed — more than 48 months have elapsed from end of AY '+ay+'.</div>';return;}

  var taxOnIncome=Math.round(income*rate/100);
  var netDiffTax=taxOnIncome-tds-advTax;
  if(netDiffTax<0) netDiffTax=0;

  var int234B=Math.round(netDiffTax*0.01*Math.ceil(diffMonths));
  var totalBase=netDiffTax+int234B;
  var addTax140B=Math.round(totalBase*addRate/100);
  var totalPayable=netDiffTax+int234B+addTax140B;

  r.className='result-box presumptive';
  var html='<div class="result-title">ITR-U Tax Computation — AY '+ay+'</div>';
  html+='<div class="result-detail">';
  html+='<h3 style="margin:10px 0 6px;color:var(--accent);">Step A — Time Window & Rate</h3>';
  html+='<table class="limits-table">';
  html+='<tr><td>AY End Date</td><td>31 March '+ayEndYear+'</td></tr>';
  html+='<tr><td>Filing Date</td><td>'+fileDate.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'})+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Applicable Window</strong></td><td><strong>'+windowLabel+' — '+addRate+'%</strong></td></tr>';
  html+='</table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step B — Tax on Additional Income</h3>';
  html+='<table class="limits-table">';
  html+='<tr><td>Additional Income</td><td>'+fmt(income)+'</td></tr>';
  html+='<tr><td>Tax @ '+rate+'%</td><td>'+fmt(taxOnIncome)+'</td></tr>';
  html+='<tr><td>(-) TDS already deducted</td><td>'+fmt(tds)+'</td></tr>';
  html+='<tr><td>(-) Advance Tax paid</td><td>'+fmt(advTax)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Net Differential Tax</strong></td><td><strong>'+fmt(netDiffTax)+'</strong></td></tr>';
  html+='</table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step C & D — Interest & Additional Tax</h3>';
  html+='<table class="limits-table">';
  html+='<tr><td>Interest u/s 234B (approx @ 1%/month for ~'+Math.ceil(diffMonths)+' months)</td><td>'+fmt(int234B)+'</td></tr>';
  html+='<tr><td>Base (Tax + Interest)</td><td>'+fmt(totalBase)+'</td></tr>';
  html+='<tr><td>Additional Tax u/s 140B @ '+addRate+'%</td><td>'+fmt(addTax140B)+'</td></tr>';
  html+='</table>';

  html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step E — Total Payable Before Filing ITR-U</h3>';
  html+='<table class="limits-table">';
  html+='<tr><td>Differential Tax</td><td>'+fmt(netDiffTax)+'</td></tr>';
  html+='<tr><td>Interest u/s 234B</td><td>'+fmt(int234B)+'</td></tr>';
  html+='<tr><td>Additional Tax u/s 140B ('+addRate+'%)</td><td>'+fmt(addTax140B)+'</td></tr>';
  html+='<tr style="background:#e8f8f5;"><td><strong>Total Amount Payable</strong></td><td><strong style="font-size:1.1rem;">'+fmt(totalPayable)+'</strong></td></tr>';
  html+='</table>';
  html+='<p style="margin-top:10px;font-size:0.82rem;color:#555;">Pay via Challan ITNS 280 — Self Assessment Tax (Code 300) on the IT Portal before filing ITR-U. Enter CIN in the ITR-U form.</p>';
  html+='</div>';
  r.innerHTML=html;
}
function resetITRU(){['itruIncome','itruTDS','itruAdvTax','itruDate'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('itruAY').value='25-26';document.getElementById('itruRate').value='30';document.getElementById('itruResult').className='result-box';document.getElementById('itruResult').innerHTML='';}


// ==================== PRESUMPTIVE TAX JS ====================
function showPresScheme(scheme){
var sections=['pres44AD','pres44ADA','pres44AE'];
var cards=['presCard44AD','presCard44ADA','presCard44AE'];
var map={ad:0,ada:1,ae:2};
sections.forEach(function(s,i){document.getElementById(s).style.display=i===map[scheme]?'block':'none';});
cards.forEach(function(c,i){document.getElementById(c).style.borderColor=i===map[scheme]?'var(--accent)':'transparent';});
}
function calc44AD(){
var turnover=parseFloat(document.getElementById('adTurnover').value)||0;
var cashR=parseFloat(document.getElementById('adCashReceipts').value)||0;
var cashP=parseFloat(document.getElementById('adCashPayments').value)||0;
var actual=parseFloat(document.getElementById('adActualProfit').value)||0;
var optOut=document.getElementById('adOptOut').value;
var r=document.getElementById('adResult');
if(turnover<=0){r.className='result-box applicable';r.innerHTML='<div class="result-title">Please enter turnover.</div>';return;}
var cashRPct=turnover>0?((cashR/turnover)*100):0;
var cashPPct=turnover>0?((cashP/turnover)*100):0;
var limit=(cashRPct<=5&&cashPPct<=5)?30000000:20000000;
var eligible=turnover<=limit;
var digitalTO=turnover-cashR;
var presDigital=Math.round(digitalTO*0.06);
var presCash=Math.round(cashR*0.08);
var presTotal=presDigital+presCash;
r.className='result-box presumptive';
var html='<div class="result-title">Section 44AD — Computation</div><div class="result-detail">';
html+='<h3 style="margin:10px 0 6px;color:var(--accent);">Step A — Turnover Limit Check</h3>';
html+='<table class="limits-table"><tr><td>Total turnover</td><td>Rs '+fmt(turnover)+'</td></tr>';
html+='<tr><td>Cash receipts</td><td>Rs '+fmt(cashR)+' ('+cashRPct.toFixed(1)+'% of total)</td></tr>';
html+='<tr><td>Cash payments</td><td>Rs '+fmt(cashP)+' ('+cashPPct.toFixed(1)+'% of total)</td></tr>';
html+='<tr><td>Applicable limit</td><td>Rs '+fmt(limit)+(limit===30000000?' (both cash ≤5%)':' (standard)')+'</td></tr>';
html+='<tr style="background:'+(eligible?'#e8f8f5':'#fde8e8')+';"><td><strong>Eligibility</strong></td><td><strong>'+(eligible?'Within limit — eligible for 44AD':'Exceeds limit — Tax Audit mandatory u/s 44AB')+'</strong></td></tr></table>';
if(optOut==='yes'){html+='<div style="margin:12px 0;padding:10px;background:#fde8e8;border:2px solid #d63031;border-radius:8px;font-size:0.88rem;color:#d63031;"><strong>You have opted out of Sec 44AD within the last 5 years.</strong> You are NOT eligible for 44AD for the next 5 Assessment Years. Tax Audit u/s 44AB is mandatory even if turnover is below the limit.</div>';}
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step B — Presumptive Income</h3>';
html+='<table class="limits-table"><tr><td>Digital/non-cash turnover</td><td>Rs '+fmt(digitalTO)+' x 6% = Rs '+fmt(presDigital)+'</td></tr>';
html+='<tr><td>Cash turnover</td><td>Rs '+fmt(cashR)+' x 8% = Rs '+fmt(presCash)+'</td></tr>';
html+='<tr style="background:#e8f8f5;"><td><strong>Total Presumptive Income u/s 44AD</strong></td><td><strong>Rs '+fmt(presTotal)+'</strong></td></tr></table>';
if(actual>0){
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step C — Actual vs Presumptive</h3>';
html+='<table class="limits-table"><tr><td>Actual profit</td><td>Rs '+fmt(actual)+'</td></tr>';
html+='<tr><td>Minimum required (presumptive)</td><td>Rs '+fmt(presTotal)+'</td></tr>';
html+='<tr style="background:'+(actual>=presTotal?'#e8f8f5':'#fde8e8')+';"><td><strong>Status</strong></td><td><strong>'+(actual>=presTotal?'Actual >= Presumptive — Can opt for 44AD, no audit needed':'Actual < Presumptive — Must declare presumptive OR opt out (audit mandatory for next 5 AYs)')+'</strong></td></tr></table>';
}
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step D — Notes</h3>';
html+='<ul style="font-size:0.88rem;margin-left:18px;line-height:1.8;"><li>Advance tax: 100% in single instalment by 15 March (not quarterly)</li><li>No separate deductions u/s 30–38 allowed (deemed included in presumptive income)</li></ul>';
html+='</div>';r.innerHTML=html;
}
function reset44AD(){['adTurnover','adCashReceipts','adCashPayments','adActualProfit'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('adOptOut').value='no';document.getElementById('adResult').className='result-box';document.getElementById('adResult').innerHTML='';}

function calc44ADA(){
var receipts=parseFloat(document.getElementById('adaReceipts').value)||0;
var cashR=parseFloat(document.getElementById('adaCashR').value)||0;
var actual=parseFloat(document.getElementById('adaActualProfit').value)||0;
var r=document.getElementById('adaResult');
if(receipts<=0){r.className='result-box applicable';r.innerHTML='<div class="result-title">Please enter gross receipts.</div>';return;}
var limit=7500000;
var eligible=receipts<=limit;
var presIncome=Math.round(receipts*0.5);
r.className='result-box presumptive';
var html='<div class="result-title">Section 44ADA — Computation</div><div class="result-detail">';
html+='<h3 style="margin:10px 0 6px;color:var(--accent);">Step A — Eligibility</h3>';
html+='<table class="limits-table"><tr><td>Gross receipts</td><td>Rs '+fmt(receipts)+'</td></tr>';
html+='<tr><td>Applicable limit</td><td>Rs '+fmt(limit)+' (w.e.f. AY 2024-25)</td></tr>';
html+='<tr style="background:'+(eligible?'#e8f8f5':'#fde8e8')+';"><td><strong>Eligibility</strong></td><td><strong>'+(eligible?'Within Rs 75 lakh — eligible':'Exceeds — Tax Audit mandatory u/s 44AB')+'</strong></td></tr></table>';
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step B — Presumptive Income</h3>';
html+='<table class="limits-table"><tr><td>Gross receipts</td><td>Rs '+fmt(receipts)+'</td></tr>';
html+='<tr style="background:#e8f8f5;"><td><strong>Presumptive income @ 50%</strong></td><td><strong>Rs '+fmt(presIncome)+'</strong></td></tr></table>';
if(actual>0){
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step C — Comparison</h3>';
html+='<table class="limits-table"><tr><td>Actual profit</td><td>Rs '+fmt(actual)+'</td></tr>';
html+='<tr><td>Presumptive (50%)</td><td>Rs '+fmt(presIncome)+'</td></tr>';
html+='<tr style="background:'+(actual>=presIncome?'#e8f8f5':'#fde8e8')+';"><td><strong>Status</strong></td><td><strong>'+(actual>=presIncome?'Actual >= 50% — Eligible for 44ADA, no audit':'Actual < 50% — Must declare 50% OR opt out (audit mandatory). NOTE: Unlike 44AD, no 5-year lock-in for 44ADA.')+'</strong></td></tr></table>';
}
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step D — Notes</h3>';
html+='<ul style="font-size:0.88rem;margin-left:18px;line-height:1.8;"><li>Advance tax: 100% single instalment by 15 March</li><li>No deductions u/s 30–38 separately allowable</li></ul></div>';
r.innerHTML=html;
}
function reset44ADA(){['adaReceipts','adaCashR','adaActualProfit'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('adaResult').className='result-box';document.getElementById('adaResult').innerHTML='';}

function calc44AE(){
var heavy=parseInt(document.getElementById('aeHeavy').value)||0;
var tonnage=parseFloat(document.getElementById('aeTonnage').value)||0;
var other=parseInt(document.getElementById('aeOther').value)||0;
var months=parseInt(document.getElementById('aeMonths').value)||12;
var actual=parseFloat(document.getElementById('aeActualProfit').value)||0;
var r=document.getElementById('aeResult');
var total=heavy+other;
if(total<=0){r.className='result-box applicable';r.innerHTML='<div class="result-title">Please enter number of vehicles.</div>';return;}
var eligible=total<=10;
var heavyIncome=Math.round(tonnage*1000*months);
var otherIncome=Math.round(other*7500*months);
var presTotal=heavyIncome+otherIncome;
r.className='result-box presumptive';
var html='<div class="result-title">Section 44AE — Computation</div><div class="result-detail">';
html+='<h3 style="margin:10px 0 6px;color:var(--accent);">Step A — Vehicle Count Check</h3>';
html+='<table class="limits-table"><tr><td>Total vehicles</td><td>'+total+' (Heavy: '+heavy+' + Other: '+other+')</td></tr>';
html+='<tr style="background:'+(eligible?'#e8f8f5':'#fde8e8')+';"><td><strong>Eligibility</strong></td><td><strong>'+(eligible?'≤ 10 vehicles — eligible for 44AE':'> 10 vehicles — not eligible, must maintain books')+'</strong></td></tr></table>';
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step B — Presumptive Income</h3>';
html+='<table class="limits-table"><thead><tr><th>Vehicle Type</th><th>Rate</th></tr></thead>';
html+='<tr><td>Heavy Goods Vehicle (GVW > 12 MT)</td><td>Rs 1,000 per ton of GVW per month</td></tr>';
html+='<tr><td>Other Vehicle (GVW ≤ 12 MT)</td><td>Rs 7,500 per vehicle per month</td></tr></table>';
html+='<table class="limits-table" style="margin-top:10px;"><tr><td>Heavy vehicles</td><td>'+tonnage+' tonnes x Rs 1,000 x '+months+' months = Rs '+fmt(heavyIncome)+'</td></tr>';
html+='<tr><td>Other vehicles</td><td>'+other+' vehicles x Rs 7,500 x '+months+' months = Rs '+fmt(otherIncome)+'</td></tr>';
html+='<tr style="background:#e8f8f5;"><td><strong>Total Presumptive Income u/s 44AE</strong></td><td><strong>Rs '+fmt(presTotal)+'</strong></td></tr></table>';
if(actual>0){
html+='<h3 style="margin:14px 0 6px;color:var(--accent);">Step C — Comparison</h3>';
html+='<table class="limits-table"><tr><td>Actual profit</td><td>Rs '+fmt(actual)+'</td></tr>';
html+='<tr><td>Presumptive income</td><td>Rs '+fmt(presTotal)+'</td></tr>';
html+='<tr><td colspan="2" style="font-size:0.85rem;color:#666;">Note: Unlike 44AD, there is NO opt-out option for 44AE. Must declare at least the presumptive amount. If actual is higher, declare higher.</td></tr></table>';
}
html+='</div>';r.innerHTML=html;
}
function reset44AE(){['aeHeavy','aeTonnage','aeOther','aeActualProfit'].forEach(function(id){document.getElementById(id).value='';});document.getElementById('aeMonths').value='12';document.getElementById('aeResult').className='result-box';document.getElementById('aeResult').innerHTML='';}


