function showROCEntity(entity){
var cards={pvt:'rocCardPvt',pub:'rocCardPub',opc:'rocCardOPC',sec8:'rocCardSec8',llp:'rocCardLLP'};
Object.keys(cards).forEach(function(k){document.getElementById(cards[k]).style.borderColor=k===entity?'var(--accent)':'transparent';});
var data=rocData[entity]||[];
var names={pvt:'Private Limited Company',pub:'Public Limited Company',opc:'One Person Company (OPC)',sec8:'Section 8 Company',llp:'LLP (Limited Liability Partnership)'};
var html='<h3 style="color:var(--primary-mid);margin-bottom:10px;">Annual Compliance — '+names[entity]+'</h3>';
html+='<table class="limits-table"><thead><tr><th>Form</th><th>Purpose</th><th>Due Date</th><th>Penalty for Default</th></tr></thead><tbody>';
data.forEach(function(d){html+='<tr><td><strong>'+d.form+'</strong></td><td>'+d.purpose+'</td><td>'+d.due+'</td><td style="font-size:0.82rem;color:#d63031;">'+d.penalty+'</td></tr>';});
html+='</tbody></table>';
document.getElementById('rocTableArea').innerHTML=html;
}
showROCEntity('pvt');

function calcROCPenalty(){
var formVal=document.getElementById('rocForm').value;
var dueStr=document.getElementById('rocDueDate').value;
var fileStr=document.getElementById('rocFilingDate').value;
var r=document.getElementById('rocPenResult');
if(!dueStr||!fileStr){r.className='result-box applicable';r.innerHTML='<div class="result-title">Please enter both dates.</div>';return;}
var due=new Date(dueStr);var file=new Date(fileStr);
var diffDays=Math.ceil((file-due)/(1000*60*60*24));
if(diffDays<=0){r.className='result-box not-applicable';r.innerHTML='<div class="result-title" style="color:#00b894;">No Penalty</div><div class="result-detail">Filed on or before due date. No late filing penalty.</div>';return;}
var penalty=0;var note='';
if(formVal==='5000'){penalty=5000;note='DIR-3 KYC: Flat fee of Rs 5,000 if filed after 30 September. DIN deactivated until KYC is completed.';}
else if(formVal==='300'){penalty=Math.min(diffDays*300,12000);note='ADT-1: Rs 300/day, maximum Rs 12,000.';}
else if(formVal==='500'){penalty=5000+(diffDays*500);note='DPT-3: Rs 5,000 first default + Rs 500/day continuing default.';}
else{var rate=parseInt(formVal)||100;penalty=diffDays*rate;note='Rate: Rs '+rate+'/day. No maximum cap — penalty compounds indefinitely.';}
r.className='result-box presumptive';
r.innerHTML='<div class="result-title">Late Filing Penalty Estimate</div><div class="result-detail"><table class="limits-table"><tr><td>Days of default</td><td>'+diffDays+' days</td></tr><tr><td>Estimated penalty</td><td style="color:#d63031;font-weight:700;">Rs '+fmt(penalty)+'</td></tr><tr><td>Note</td><td style="font-size:0.85rem;">'+note+'</td></tr><tr><td colspan="2" style="font-size:0.82rem;color:#666;">Actual fee on MCA portal may vary — always verify on mca.gov.in before filing.</td></tr></table></div>';
}
function resetROCPenalty(){document.getElementById('rocDueDate').value='';document.getElementById('rocFilingDate').value='';document.getElementById('rocPenResult').className='result-box';document.getElementById('rocPenResult').innerHTML='';}


